// 环境变量设置（支持周度/月度模式）
const inputData = $input.all()[0].json;
const mode = inputData.mode || 'monthly'; // 'weekly' | 'monthly'

let targetPeriod, targetYYYYMM, reportType;

if (mode === 'weekly') {
  // 周度模式：计算上周时间范围
  const today = new Date();
  const dayOfWeek = today.getDay();
  const daysToSubtract = dayOfWeek === 0 ? 13 : dayOfWeek + 6;
  const lastMonday = new Date(today);
  lastMonday.setDate(today.getDate() - daysToSubtract);
  const lastSunday = new Date(lastMonday);
  lastSunday.setDate(lastMonday.getDate() + 6);

  const formatDate = (date) => {
    const y = date.getFullYear();
    const m = String(date.getMonth() + 1).padStart(2, '0');
    const d = String(date.getDate()).padStart(2, '0');
    return `${y}${m}${d}`;
  };

  targetPeriod = `${formatDate(lastMonday)}-${formatDate(lastSunday)}`;
  targetYYYYMM = formatDate(lastMonday).substring(0, 6);
  reportType = 'weekly';
} else {
  // 月度模式：计算上个月
  const today = new Date();
  const lastMonth = new Date(today.getFullYear(), today.getMonth() - 1, 1);
  const year = lastMonth.getFullYear();
  const month = String(lastMonth.getMonth() + 1).padStart(2, '0');
  targetPeriod = `${year}年${month}月`;
  targetYYYYMM = `${year}${month}`;
  reportType = 'monthly';
}

return [{
  json: {
    mode,
    report_type: reportType,
    target_period: targetPeriod,
    target_yyyy_mm: targetYYYYMM,
    step: 1,
    step_name: "环境变量设置",
    status: "completed",
    timestamp: new Date().toISOString()
  }
}];

